{  "pattern": "fabs(fneg(x)) -> fabs(x)",
  "generalization": "For any floating-point type (including vectors), the pattern `fabs(fneg(x))` can be simplified to `fabs(x)` because the absolute value operation removes the sign, making the preceding negation irrelevant. This holds for all floating-point types, with poison/undef semantics, and preserves fast-math flags from the fneg operation.",
  "testcases": [
    {
      "name": "scalar_float_basic",
      "ir": "define float @test(float %x) {
  %neg = fneg float %x
  %abs = call float @llvm.fabs.f32(float %neg)
  ret float %abs
}",
      "expected_optimized_ir": "define float @test(float %x) {
  %abs = call float @llvm.fabs.f32(float %x)
  ret float %abs
}"
    },
    {
      "name": "scalar_double",
      "ir": "define double @test(double %x) {
  %neg = fneg double %x
  %abs = call double @llvm.fabs.f64(double %neg)
  ret double %abs
}",
      "expected_optimized_ir": "define double @test(double %x) {
  %abs = call double @llvm.fabs.f64(double %x)
  ret double %abs
}"
    },
    {
      "name": "scalar_half",
      "ir": "define half @test(half %x) {
  %neg = fneg half %x
  %abs = call half @llvm.fabs.f16(half %neg)
  ret half %abs
}",
      "expected_optimized_ir": "define half @test(half %x) {
  %abs = call half @llvm.fabs.f16(half %x)
  ret half %abs
}"
    },
    {
      "name": "vector_fixed_v4f32",
      "ir": "define <4 x float> @test(<4 x float> %x) {
  %neg = fneg <4 x float> %x
  %abs = call <4 x float> @llvm.fabs.v4f32(<4 x float> %neg)
  ret <4 x float> %abs
}",
      "expected_optimized_ir": "define <4 x float> @test(<4 x float> %x) {
  %abs = call <4 x float> @llvm.fabs.v4f32(<4 x float> %x)
  ret <4 x float> %abs
}"
    },
    {
      "name": "vector_fixed_v2f64",
      "ir": "define <2 x double> @test(<2 x double> %x) {
  %neg = fneg <2 x double> %x
  %abs = call <2 x double> @llvm.fabs.v2f64(<2 x double> %neg)
  ret <2 x double> %abs
}",
      "expected_optimized_ir": "define <2 x double> @test(<2 x double> %x) {
  %abs = call <2 x double> @llvm.fabs.v2f64(<2 x double> %x)
  ret <2 x double> %abs
}"
    },
    {
      "name": "vector_scalable_vscale_f32",
      "ir": "define <vscale x 4 x float> @test(<vscale x 4 x float> %x) {
  %neg = fneg <vscale x 4 x float> %x
  %abs = call <vscale x 4 x float> @llvm.fabs.nxv4f32(<vscale x 4 x float> %neg)
  ret <vscale x 4 x float> %abs
}",
      "expected_optimized_ir": "define <vscale x 4 x float> @test(<vscale x 4 x float> %x) {
  %abs = call <vscale x 4 x float> @llvm.fabs.nxv4f32(<vscale x 4 x float> %x)
  ret <vscale x 4 x float> %abs
}"
    },
    {
      "name": "with_fastmath_flags",
      "ir": "define float @test(float %x) {
  %neg = fneg fast float %x
  %abs = call float @llvm.fabs.f32(float %neg)
  ret float %abs
}",
      "expected_optimized_ir": "define float @test(float %x) {
  %abs = call float @llvm.fabs.f32(float %x)
  ret float %abs
}"
    },
    {
      "name": "with_multiple_uses_fneg",
      "ir": "define float @test(float %x, float* %p) {
  %neg = fneg float %x
  %abs = call float @llvm.fabs.f32(float %neg)
  store float %neg, float* %p
  ret float %abs
}",
      "expected_optimized_ir": "define float @test(float %x, float* %p) {
  %neg = fneg float %x
  %abs = call float @llvm.fabs.f32(float %x)
  store float %neg, float* %p
  ret float %abs
}"
    },
    {
      "name": "fneg_via_fmul",
      "ir": "define float @test(float %x) {
  %neg = fmul float %x, -1.0
  %abs = call float @llvm.fabs.f32(float %neg)
  ret float %abs
}",
      "expected_optimized_ir": "define float @test(float %x) {
  %abs = call float @llvm.fabs.f32(float %x)
  ret float %abs
}"
    },
    {
      "name": "fneg_via_fmul_vector_splat",
      "ir": "define <4 x float> @test(<4 x float> %x) {
