  %neg_splat = shufflevector <4 x float> %splat, <4 x float> poison, <4 x i32> zeroinitializer
  %neg = fmul <4 x float> %x, %neg_splat
  %abs = call <4 x float> @llvm.fabs.v4f32(<4 x float> %neg)
  ret <4 x float> %abs
}",
      "expected_optimized_ir": "define <4 x float> @test(<4 x float> %x) {
