    },
    {
      "name": "fabs_fneg_chain",
      "ir": "define float @test(float %x) {
  %neg1 = fneg float %x
  %abs1 = call float @llvm.fabs.f32(float %neg1)
  %neg2 = fneg float %abs1
  %abs2 = call float @llvm.fabs.f32(float %neg2)
  ret float %abs2
}",
      "expected_optimized_ir": "define float @test(float %x) {
  %abs = call float @llvm.fabs.f32(float %x)
  ret float %abs
}"
    },
    {
      "name": "fneg_fabs_commuted",
      "ir": "define float @test(float %x) {
  %abs = call float @llvm.fabs.f32(float %x)
  %neg = fneg float %abs
  ret float %neg
}",
      "expected_optimized_ir": "define float @test(float %x) {
  %abs = call float @llvm.fabs.f32(float %x)
  ret float %abs
}",
      "note": "This is a different pattern: fneg(fabs(x)) -> fabs(x). Should be handled separately but demonstrates similar sign-removal property."
    },
    {
      "name": "with_undef_element_vector",
      "ir": "define <4 x float> @test(<4 x float> %x) {
  %neg = fneg <4 x float> %x
  %abs = call <4 x float> @llvm.fabs.v4f32(<4 x float> %neg)
  ret <4 x float> %abs
}",
      "expected_optimized_ir": "define <4 x float> @test(<4 x float> %x) {
  %abs = call <4 x float> @llvm.fabs.v4f32(<4 x float> %x)
  ret <4 x float> %abs
}",
      "note": "Undef/poison elements in vectors are safe because fabs(poison) = poison and fneg(poison) = poison."
    },
    {
      "name": "fneg_fabs_with_nnan_ninf",
      "ir": "define float @test(float %x) {
