}",
      "expected_optimized_ir": "define float @test(float %x) {
  %abs = call float @llvm.fabs.f32(float %x)
  ret float %abs
}"
    },
    {
      "name": "bf16_type",
      "ir": "define bfloat @test(bfloat %x) {
  %neg = fneg bfloat %x
  %abs = call bfloat @llvm.fabs.bf16(bfloat %neg)
  ret bfloat %abs
}",
      "expected_optimized_ir": "define bfloat @test(bfloat %x) {
  %abs = call bfloat @llvm.fabs.bf16(bfloat %x)
  ret bfloat %abs
}"
    }
  ]
}

